use chrono::{DateTime, Utc};
use uuid::Uuid;

use super::context::ContextId;
use super::project::ProjectId;
use super::todo_title::TodoTitle;
use super::user::UserId;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct NextActionId(Uuid);

impl Default for NextActionId {
    fn default() -> Self {
        Self::new()
    }
}

impl NextActionId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }

    pub fn from_uuid(uuid: Uuid) -> Self {
        Self(uuid)
    }

    pub fn as_uuid(&self) -> &Uuid {
        &self.0
    }
}

/// A concrete, physical action ready to do. Has a context (required) and
/// an optional project link (projects come in Step 6, so project_id is
/// nullable for now).
///
/// State machine:
///   Active --complete()--> Completed
///
/// Completed actions are removed from the active Next Actions list.
#[derive(Debug, Clone)]
pub enum NextAction {
    Active {
        id: NextActionId,
        user_id: UserId,
        context_id: ContextId,
        project_id: Option<ProjectId>,
        title: TodoTitle,
        created_at: DateTime<Utc>,
    },
    Completed {
        id: NextActionId,
        user_id: UserId,
        context_id: ContextId,
        project_id: Option<ProjectId>,
        title: TodoTitle,
        created_at: DateTime<Utc>,
        completed_at: DateTime<Utc>,
    },
}

impl NextAction {
    pub fn new(user_id: UserId, context_id: ContextId, title: TodoTitle) -> Self {
        Self::Active {
            id: NextActionId::new(),
            user_id,
            context_id,
            project_id: None,
            title,
            created_at: Utc::now(),
        }
    }

    pub fn new_for_project(
        user_id: UserId,
        context_id: ContextId,
        project_id: ProjectId,
        title: TodoTitle,
    ) -> Self {
        Self::Active {
            id: NextActionId::new(),
            user_id,
            context_id,
            project_id: Some(project_id),
            title,
            created_at: Utc::now(),
        }
    }

    pub fn from_parts(
        id: NextActionId,
        user_id: UserId,
        context_id: ContextId,
        project_id: Option<ProjectId>,
        title: TodoTitle,
        created_at: DateTime<Utc>,
        completed_at: Option<DateTime<Utc>>,
    ) -> Self {
        match completed_at {
            Some(completed_at) => Self::Completed {
                id,
                user_id,
                context_id,
                project_id,
                title,
                created_at,
                completed_at,
            },
            None => Self::Active {
                id,
                user_id,
                context_id,
                project_id,
                title,
                created_at,
            },
        }
    }

    pub fn id(&self) -> &NextActionId {
        match self {
            Self::Active { id, .. } | Self::Completed { id, .. } => id,
        }
    }

    pub fn user_id(&self) -> &UserId {
        match self {
            Self::Active { user_id, .. } | Self::Completed { user_id, .. } => user_id,
        }
    }

    pub fn context_id(&self) -> &ContextId {
        match self {
            Self::Active { context_id, .. } | Self::Completed { context_id, .. } => context_id,
        }
    }

    pub fn project_id(&self) -> Option<&ProjectId> {
        match self {
            Self::Active { project_id, .. } | Self::Completed { project_id, .. } => {
                project_id.as_ref()
            }
        }
    }

    pub fn title(&self) -> &TodoTitle {
        match self {
            Self::Active { title, .. } | Self::Completed { title, .. } => title,
        }
    }

    pub fn created_at(&self) -> &DateTime<Utc> {
        match self {
            Self::Active { created_at, .. } | Self::Completed { created_at, .. } => created_at,
        }
    }

    pub fn is_active(&self) -> bool {
        matches!(self, Self::Active { .. })
    }

    pub fn is_completed(&self) -> bool {
        matches!(self, Self::Completed { .. })
    }

    /// Transitions an Active next action to Completed.
    /// If already completed, returns self unchanged.
    pub fn complete(self) -> Self {
        match self {
            Self::Active {
                id,
                user_id,
                context_id,
                project_id,
                title,
                created_at,
            } => Self::Completed {
                id,
                user_id,
                context_id,
                project_id,
                title,
                created_at,
                completed_at: Utc::now(),
            },
            completed @ Self::Completed { .. } => completed,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn next_action_id_is_unique() {
        let id1 = NextActionId::new();
        let id2 = NextActionId::new();
        assert_ne!(id1, id2);
    }

    #[test]
    fn next_action_id_from_uuid_roundtrips() {
        let uuid = Uuid::new_v4();
        let id = NextActionId::from_uuid(uuid);
        assert_eq!(id.as_uuid(), &uuid);
    }

    #[test]
    fn new_next_action_is_active() {
        let user_id = UserId::new();
        let context_id = ContextId::new();
        let title = TodoTitle::parse("Buy groceries".to_string()).unwrap();
        let action = NextAction::new(user_id, context_id, title);

        assert!(action.is_active());
        assert!(!action.is_completed());
        assert_eq!(action.title().as_str(), "Buy groceries");
    }

    #[test]
    fn new_next_action_has_user_and_context() {
        let user_id = UserId::new();
        let context_id = ContextId::new();
        let title = TodoTitle::parse("Call dentist".to_string()).unwrap();
        let action = NextAction::new(user_id.clone(), context_id.clone(), title);

        assert_eq!(action.user_id(), &user_id);
        assert_eq!(action.context_id(), &context_id);
    }

    #[test]
    fn complete_transitions_active_to_completed() {
        let action = NextAction::new(
            UserId::new(),
            ContextId::new(),
            TodoTitle::parse("File taxes".to_string()).unwrap(),
        );

        let completed = action.complete();
        assert!(completed.is_completed());
        assert!(!completed.is_active());
    }

    #[test]
    fn complete_preserves_id_and_fields() {
        let user_id = UserId::new();
        let context_id = ContextId::new();
        let title = TodoTitle::parse("Send email".to_string()).unwrap();
        let action = NextAction::new(user_id.clone(), context_id.clone(), title);
        let id = action.id().clone();

        let completed = action.complete();
        assert_eq!(completed.id(), &id);
        assert_eq!(completed.user_id(), &user_id);
        assert_eq!(completed.context_id(), &context_id);
        assert_eq!(completed.title().as_str(), "Send email");
    }

    #[test]
    fn complete_is_noop_on_completed_action() {
        let action = NextAction::new(
            UserId::new(),
            ContextId::new(),
            TodoTitle::parse("Already done".to_string()).unwrap(),
        );
        let completed = action.complete();
        assert!(completed.is_completed());

        // Completing again should not change anything
        let still_completed = completed.complete();
        assert!(still_completed.is_completed());
    }

    #[test]
    fn from_parts_creates_active_when_no_completed_at() {
        let id = NextActionId::new();
        let user_id = UserId::new();
        let context_id = ContextId::new();
        let title = TodoTitle::parse("Test".to_string()).unwrap();
        let now = Utc::now();

        let action = NextAction::from_parts(
            id.clone(),
            user_id.clone(),
            context_id.clone(),
            None,
            title,
            now,
            None,
        );

        assert!(action.is_active());
        assert_eq!(action.id(), &id);
        assert_eq!(action.user_id(), &user_id);
        assert_eq!(action.context_id(), &context_id);
        assert_eq!(action.created_at(), &now);
    }

    #[test]
    fn from_parts_creates_completed_when_completed_at_present() {
        let id = NextActionId::new();
        let user_id = UserId::new();
        let context_id = ContextId::new();
        let title = TodoTitle::parse("Done task".to_string()).unwrap();
        let created = Utc::now();
        let completed = Utc::now();

        let action = NextAction::from_parts(
            id.clone(),
            user_id.clone(),
            context_id.clone(),
            None,
            title,
            created,
            Some(completed),
        );

        assert!(action.is_completed());
        assert_eq!(action.id(), &id);
    }
}

use chrono::{DateTime, Utc};
use sqlx::{PgExecutor, PgPool};
use uuid::Uuid;

use crate::domain::{ContextId, NextAction, NextActionId, ProjectId, TodoTitle, UserId};

struct NextActionRecord {
    id: Uuid,
    user_id: Uuid,
    context_id: Uuid,
    project_id: Option<Uuid>,
    title: String,
    created_at: DateTime<Utc>,
    completed_at: Option<DateTime<Utc>>,
}

impl NextActionRecord {
    fn into_domain(self) -> NextAction {
        let id = NextActionId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let context_id = ContextId::from_uuid(self.context_id);
        let project_id = self.project_id.map(ProjectId::from_uuid);
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");

        NextAction::from_parts(
            id,
            user_id,
            context_id,
            project_id,
            title,
            self.created_at,
            self.completed_at,
        )
    }
}

pub async fn insert_next_action(
    executor: impl PgExecutor<'_>,
    action: &NextAction,
) -> Result<(), sqlx::Error> {
    let completed_at: Option<&DateTime<Utc>> = match action {
        NextAction::Completed { completed_at, .. } => Some(completed_at),
        NextAction::Active { .. } => None,
    };

    let project_id = action.project_id().map(|pid| *pid.as_uuid());

    sqlx::query!(
        r#"INSERT INTO next_actions (id, user_id, context_id, project_id, title, created_at, completed_at)
           VALUES ($1, $2, $3, $4, $5, $6 :: timestamptz, $7 :: timestamptz)"#,
        action.id().as_uuid(),
        action.user_id().as_uuid(),
        action.context_id().as_uuid(),
        project_id as Option<Uuid>,
        action.title().as_str(),
        action.created_at() as &DateTime<Utc>,
        completed_at as Option<&DateTime<Utc>>,
    )
    .execute(executor)
    .await?;
    Ok(())
}

pub async fn find_active_next_actions_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<NextAction>, sqlx::Error> {
    let records = sqlx::query_as!(
        NextActionRecord,
        r#"SELECT id, user_id, context_id, project_id, title,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>"
           FROM next_actions
           WHERE user_id = $1 AND completed_at IS NULL
           ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records
        .into_iter()
        .map(|r: NextActionRecord| r.into_domain())
        .collect())
}

pub async fn find_active_next_actions_by_user_and_context(
    pool: &PgPool,
    user_id: &UserId,
    context_id: &ContextId,
) -> Result<Vec<NextAction>, sqlx::Error> {
    let records = sqlx::query_as!(
        NextActionRecord,
        r#"SELECT id, user_id, context_id, project_id, title,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>"
           FROM next_actions
           WHERE user_id = $1 AND context_id = $2 AND completed_at IS NULL
           ORDER BY created_at ASC"#,
        user_id.as_uuid(),
        context_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records
        .into_iter()
        .map(|r: NextActionRecord| r.into_domain())
        .collect())
}

pub async fn find_next_action_by_id(
    pool: &PgPool,
    action_id: &NextActionId,
) -> Result<Option<NextAction>, sqlx::Error> {
    let record: Option<NextActionRecord> = sqlx::query_as!(
        NextActionRecord,
        r#"SELECT id, user_id, context_id, project_id, title,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>"
           FROM next_actions WHERE id = $1"#,
        action_id.as_uuid(),
    )
    .fetch_optional(pool)
    .await?;

    Ok(record.map(|r: NextActionRecord| r.into_domain()))
}

pub async fn complete_next_action(
    pool: &PgPool,
    action_id: &NextActionId,
    completed_at: &DateTime<Utc>,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE next_actions SET completed_at = $1 :: timestamptz WHERE id = $2"#,
        completed_at as &DateTime<Utc>,
        action_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn delete_next_action(
    pool: &PgPool,
    action_id: &NextActionId,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM next_actions WHERE id = $1"#,
        action_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn update_next_action_title(
    pool: &PgPool,
    action_id: &NextActionId,
    title: &TodoTitle,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE next_actions SET title = $1 WHERE id = $2"#,
        title.as_str(),
        action_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn count_active_next_actions(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM next_actions WHERE user_id = $1 AND completed_at IS NULL"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

pub async fn find_next_actions_by_project(
    pool: &PgPool,
    project_id: &ProjectId,
) -> Result<Vec<NextAction>, sqlx::Error> {
    let records = sqlx::query_as!(
        NextActionRecord,
        r#"SELECT id, user_id, context_id, project_id, title,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>"
           FROM next_actions
           WHERE project_id = $1
           ORDER BY completed_at NULLS FIRST, created_at ASC"#,
        project_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records.into_iter().map(|r| r.into_domain()).collect())
}

use chrono::{DateTime, Utc};
use sqlx::{PgExecutor, PgPool};
use uuid::Uuid;

use crate::domain::{InboxItem, InboxItemId, TodoTitle, UserId};

struct InboxRecord {
    id: Uuid,
    user_id: Uuid,
    title: String,
    created_at: DateTime<Utc>,
}

impl InboxRecord {
    fn into_domain(self) -> InboxItem {
        let id = InboxItemId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");

        InboxItem::from_parts(id, user_id, title, self.created_at)
    }
}

pub async fn insert_inbox_item(pool: &PgPool, item: &InboxItem) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"INSERT INTO inbox_items (id, user_id, title, created_at)
           VALUES ($1, $2, $3, $4 :: timestamptz)"#,
        item.id().as_uuid(),
        item.user_id().as_uuid(),
        item.title().as_str(),
        item.created_at() as &DateTime<Utc>,
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_inbox_items_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<InboxItem>, sqlx::Error> {
    let records = sqlx::query_as!(
        InboxRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>"
           FROM inbox_items WHERE user_id = $1 ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records
        .into_iter()
        .map(|r: InboxRecord| r.into_domain())
        .collect())
}

pub async fn count_inbox_items(pool: &PgPool, user_id: &UserId) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM inbox_items WHERE user_id = $1"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

pub async fn delete_inbox_item(
    executor: impl PgExecutor<'_>,
    item_id: &InboxItemId,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM inbox_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .execute(executor)
    .await?;
    Ok(())
}

pub async fn find_inbox_item_by_id(
    executor: impl PgExecutor<'_>,
    item_id: &InboxItemId,
) -> Result<Option<InboxItem>, sqlx::Error> {
    let record: Option<InboxRecord> = sqlx::query_as!(
        InboxRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>"
           FROM inbox_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .fetch_optional(executor)
    .await?;

    Ok(record.map(|r: InboxRecord| r.into_domain()))
}
